# 同名分頁先刪再建
try:
    sh.del_worksheet(sh.worksheet(TAB_NAME))
except gspread.WorksheetNotFound:
    pass

ws = sh.add_worksheet(title=TAB_NAME, rows=len(rows) + 5, cols=len(HEADER))
ws.update(range_name="A1", values=rows)

ws.format("A1:K1", {"backgroundColor": {"red": 0.26, "green": 0.45, "blue": 0.36},
                    "horizontalAlignment": "CENTER",
                    "textFormat": {"bold": True, "foregroundColor": {"red": 1, "green": 1, "blue": 1}}})
ws.freeze(rows=1, cols=3)
ws.format(f"A2:K{len(rows)}", {"wrapStrategy": "WRAP", "verticalAlignment": "TOP"})

stage_color = {
    "trans":  {"red": 0.93, "green": 0.88, "blue": 0.95},
    "vienna": {"red": 0.87, "green": 0.93, "blue": 0.85},
    "alpine": {"red": 0.82, "green": 0.90, "blue": 0.93},
    "nice":   {"red": 1.00, "green": 0.96, "blue": 0.82},
    "paris":  {"red": 0.98, "green": 0.88, "blue": 0.88},
}
def stage(r):
    d = int(r[0])
    if d == 1 or d == 23: return "trans"
    if 2 <= d <= 5: return "vienna"
    if 6 <= d <= 9: return "alpine"
    if d == 10: return "trans"
    if 11 <= d <= 15: return "nice"
    if d == 16: return "trans"
    if 17 <= d <= 22: return "paris"
    return "trans"

batch, start, prev = [], 2, stage(rows[1])
for i, r in enumerate(rows[2:], start=3):
    cur = stage(r)
    if cur != prev:
        batch.append({"range": f"A{start}:K{i-1}", "format": {"backgroundColor": stage_color[prev]}})
        start, prev = i, cur
batch.append({"range": f"A{start}:K{len(rows)}", "format": {"backgroundColor": stage_color[prev]}})
